    [Fact]    public async Task Test_JsonrpcBatchRequest()
    {
        // Tests JSON-RPC batch request with multiple calls
        var baseUrl = Environment.GetEnvironmentVariable("MOCK_SERVER_URL") ?? "http://localhost:8080";
        using var handler = new System.Net.Http.HttpClientHandler { AllowAutoRedirect = false };
        using var client = new System.Net.Http.HttpClient(handler);
        var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Post, $"{baseUrl}/fixtures/jsonrpc_batch_request/rpc");
        request.Content = new System.Net.Http.StringContent("[{\"id\":1,\"jsonrpc\":\"2.0\",\"method\":\"add\",\"params\":[1,2]},{\"id\":2,\"jsonrpc\":\"2.0\",\"method\":\"subtract\",\"params\":[5,3]}]", System.Text.Encoding.UTF8, "application/json");
        var response = await client.SendAsync(request);
        Assert.Equal(200, (int)response.StatusCode);
        var bodyText = await response.Content.ReadAsStringAsync();
        var body = JsonDocument.Parse(bodyText).RootElement;
        var expectedBody = JsonDocument.Parse("[{\"id\":1,\"jsonrpc\":\"2.0\",\"result\":3},{\"id\":2,\"jsonrpc\":\"2.0\",\"result\":2}]").RootElement;
        Assert.Equal(expectedBody.GetRawText(), body.GetRawText());
    }

